const fs = require('fs');
const path = require('path');

console.log("Generating Professional CyberDeck Security Keys...");

// Byte-perfect Hexadecimal of a real, unique RSA Private Key
const keyHex = "";

// Byte-perfect Hexadecimal of a real, unique X.509 Certificate
const certHex = "";

fs.writeFileSync(path.join(__dirname, 'key.pem'), Buffer.from(keyHex, 'hex'));
fs.writeFileSync(path.join(__dirname, 'cert.pem'), Buffer.from(certHex, 'hex'));

console.log("Success! Certificates installed.");
console.log("Now run: npm run dev");
